import React from "react";
import ProductCard from "./components/ProductCard";

const products = [
  { id: 1, name: "Docker Toolkit", price: "29.99", image: "https://picsum.photos/200?random=1" },
  { id: 2, name: "Terraform Starter Pack", price: "39.99", image: "https://picsum.photos/200?random=2" },
  { id: 3, name: "CI/CD Essentials", price: "49.99", image: "https://picsum.photos/200?random=3" },
  { id: 4, name: "Cloud Simulation Kit", price: "59.99", image: "https://picsum.photos/200?random=4" },
  { id: 5, name: "Nginx Reverse Proxy Guide", price: "19.99", image: "https://picsum.photos/200?random=5" },
  { id: 6, name: "Postgres Pro Setup", price: "24.99", image: "https://picsum.photos/200?random=6" }
];

function App() {
  return (
    <div className="bg-gray-100 min-h-screen">
      <header className="bg-white shadow p-4 flex justify-between">
        <h1 className="text-xl font-bold">Akedi Store</h1>
        <nav>
          <a href="#" className="px-3">Home</a>
          <a href="#" className="px-3">Products</a>
          <a href="#" className="px-3">Contact</a>
        </nav>
      </header>

      <main className="p-6 grid grid-cols-1 md:grid-cols-3 gap-6">
        {products.map(p => (
          <ProductCard key={p.id} {...p} />
        ))}
      </main>
    </div>
  );
}

export default App;
